  INSERT INTO public.posts (author_id, title, excerpt, category, type, likes_count, comments_count, created_at) VALUES
  (v_author_id, 'Как я выстроила стратегию контента на год вперёд', 'Разбираю свой процесс планирования: от анализа аудитории до конкретных рубрик и форматов.', 'insight', 'text', 24, 5, now() - interval '1 day'),
  (v_author_id, 'Разбор: почему Reels больше не работают как раньше', 'Алгоритм изменился. Вот что я заметила на своём профиле и как скорректировала подход.', 'razobory', 'text', 41, 12, now() - interval '2 days'),
  (v_author_id, 'Съёмка без студии: моя домашняя установка для лайфстайл-фото', 'Показываю оборудование, которое использую дома, и как добиться чистого света.', 'syomka', 'photo', 67, 8, now() - interval '3 days'),
  (v_author_id, 'Почему я перестала гнаться за трендами в Reels', 'Три месяца экспериментов с вертикальным видео — что работает, а что нет.', 'reels', 'video', 33, 6, now() - interval '4 days'),
  (v_author_id, 'Сотрудничество с брендами: как не потерять себя', 'Мой чек-лист для оценки партнёрских предложений и переговоров об условиях.', 'brendy', 'text', 19, 3, now() - interval '5 days'),
  (v_author_id, 'Тема месяца: выгорание контент-мейкера', 'Что мне помогло вернуться к работе после двух месяцев молчания.', 'tema', 'text', 88, 21, now() - interval '6 days'),
  (v_author_id, 'Инсайт: аудитория не хочет идеальности', 'Почему мои «несовершенные» посты собирают больше охватов, чем тщательно отредактированные.', 'insight', 'text', 55, 14, now() - interval '7 days'),
  (v_author_id, 'Разбор профиля: что бы я сделала иначе', 'Анализирую один из лучших профилей в нише с точки зрения стратегии и контента.', 'razobory', 'text', 29, 7, now() - interval '8 days'),
  (v_author_id, 'Lightroom-пресеты для тёплой осенней эстетики', 'Делюсь пресетами, которые использую для единого стиля в ленте.', 'syomka', 'photo', 74, 18, now() - interval '9 days'),
  (v_author_id, 'Структура моего контент-плана на месяц', 'Шаблон и процесс планирования: как я поддерживаю баланс между личным и продающим.', 'insight', 'text', 62, 11, now() - interval '10 days'),
  (v_author_id, 'Reels за 30 минут: моя быстрая установка', 'Как снимать видео без лишних затрат времени, сохраняя качество.', 'reels', 'video', 47, 9, now() - interval '11 days'),
  (v_author_id, 'Как выбираю бренды для долгосрочного партнёрства', 'Критерии, которые помогают мне не ошибиться с выбором рекламодателя.', 'brendy', 'text', 38, 4, now() - interval '12 days'),
  (v_author_id, 'Творческий кризис: нормально и как с этим жить', 'Честный разговор о периодах, когда совсем не хочется снимать или писать.', 'tema', 'text', 91, 25, now() - interval '13 days');
